import statistics
import time
from concurrent.futures import ThreadPoolExecutor, wait
from threading import Lock
from typing import Any, Dict

import click
import requests

######################
# Boring setup stuff #
######################

PORTER_URLS = {
    "mainnet": "https://porter.nucypher.io",
    "lynx": "https://porter-lynx.nucypher.io",
}

COHORT_3_SIGNING_REQUESTS = {
    "encrypted_signing_requests": {
        "0x210eeAC07542F815ebB6FD6689637D8cA2689392": "",
        "0x48C8039c32F4c6f5cb206A5911C8Ae814929C16B": "",
        "0xb15d5A4e2be34f4bE154A1b08a94Ab920FfD8A41": "",
    },
    "threshold": 2,
}

COHORT_1_SIGNING_REQUESTS = {
    "encrypted_signing_requests": {
        "0x210eeAC07542F815ebB6FD6689637D8cA2689392": "",
        "0x48C8039c32F4c6f5cb206A5911C8Ae814929C16B": "",
        "0xb15d5A4e2be34f4bE154A1b08a94Ab920FfD8A41": "",
    },
    "threshold": 2,
}

COHORT_4_MAINNET_SIGNING_REQUESTS = {
    "encrypted_signing_requests": {
        "0x97d065B567cc4543D20dffaa7009f9aDe64d7E26": "",
        "0xA829c2E33907Ab03d27d5dBb39eFFd8386112789": "",
        "0xb011b6794F271B1d8D2328eDf332535343CB4D44": "",
        "0xB98a82aB97171504bf9eA0aC62A3f34BffE5F510": "",
        "0xc1268db05E7bD38BD85b2C3Fef80F8968a2c933A": "",
        "0xD680B01503CF95A489010dA7409980060991D096": "",
        "0xF9283aC13aEc8a2B60a56A82F1f5E4dA1742CCf8": "",
    },
    "threshold": 4
}


SIGNING_REQUESTS = {
    1: COHORT_1_SIGNING_REQUESTS,
    3: COHORT_3_SIGNING_REQUESTS,
    4: COHORT_4_MAINNET_SIGNING_REQUESTS,
}


class AtomicCounter:
    def __init__(self):
        self.value = 0
        self._lock = Lock()

    def increment(self):
        with self._lock:
            self.value += 1

    def get_value(self):
        with self._lock:
            return self.value


class StatsCollector:
    def __init__(self):
        self._lock = Lock()
        self.values = []

    def add_value(self, value):
        with self._lock:
            self.values.append(value)

    def get_values(self):
        with self._lock:
            return self.values.copy()


def send_porter_request(
    domain: str,
    encrypted_signing_requests: Dict[str, Any],
    failures: AtomicCounter,
    stats_collector: StatsCollector,
) -> None:
    porter_url = PORTER_URLS[domain]
    start = time.perf_counter()
    try:
        response = requests.post(
            f"{porter_url}/sign", json=encrypted_signing_requests
        )
        time_taken = time.perf_counter() - start
        response.raise_for_status()

        response_data = response.json()["result"]["signing_results"]
        signing_responses = response_data.get("encrypted_signature_responses", [])
        if len(signing_responses) < encrypted_signing_requests["threshold"]:
            raise ValueError(f"Not enough signing results; errors: {response_data['errors']}")

        stats_collector.add_value(time_taken)
    except Exception as e:
        failures.increment()
        click.secho(f"![FAILURE] Porter request failed: {e}", fg="red")


@click.command()
@click.option(
    "--num-threads",
    "-t",
    help="Number of threads to use for the stress test.",
    type=click.INT,
    default=30,
)
@click.option(
    "--test-executions",
    "-e",
    help="Number of total test executions to perform.",
    type=click.INT,
    default=100,
)
@click.option(
    "--timeout",
    help="Maximum time to wait for all threads to complete before timing out (in seconds).",
    type=click.INT,
    default=120,
)
@click.option(
    "--cohort-id",
    help="Cohort to use for the signing requests.",
    type=click.Choice(list(SIGNING_REQUESTS.keys())),
    required=True,
)
@click.option(
    "--domain",
    help="Porter domain to send signing requests to.",
    type=click.Choice(["mainnet", "lynx"]),
    required=True,
)
def signing_stress_test(
    num_threads: int,
    test_executions: int,
    timeout: int,
    cohort_id: int,
    domain: str,
) -> None:

    if cohort_id == 4 and domain != "mainnet":
        raise click.UsageError(
            "Cohort 4 signing requests are only valid for the mainnet domain."
        )
    if cohort_id != 4 and domain != "lynx":
        raise click.UsageError(
            f"Cohort {cohort_id} signing requests are only valid for the lynx domain."
        )

    failures = AtomicCounter()
    stats_collector = StatsCollector()
    start_time = time.perf_counter()
    signing_requests = SIGNING_REQUESTS[cohort_id]
    try:
        # use thread pool
        with ThreadPoolExecutor(num_threads) as executor:
            futures = []
            for _ in range(test_executions):
                f = executor.submit(
                    send_porter_request, domain, signing_requests, failures, stats_collector
                )
                futures.append(f)

            wait(futures, timeout=timeout)  # wait until done or timeout
    finally:
        time_taken = time.perf_counter() - start_time

    click.echo(
        f"\n[RESULTS]: Node signing stress test with {num_threads} threads and {test_executions} test executions"
    )
    click.echo(f"\nTotal time: {time_taken:.2f}s")
    click.echo(f"Cohort ID: {cohort_id}")
    click.secho(
        f"Num failures: {failures.get_value()}",
        fg="red" if failures.get_value() > 0 else None,
    )
    values = stats_collector.get_values()
    if values:
        click.echo(f"Statistics for successful requests: {len(values)}")
        click.echo(f"\tMean: {statistics.mean(values):.2f}s")
        click.echo(f"\tMedian: {statistics.median(values):.2f}s")
        click.echo(f"\tMax: {max(values):.2f}s")
        click.echo(f"\tMin: {min(values):.2f}s")
        if len(values) >= 2:
            percentiles = statistics.quantiles(data=values, n=100, method="inclusive")
            click.echo(f"\tp90: {percentiles[89]:0.2f}s")  # 90%
            click.echo(f"\tp95: {percentiles[94]:0.2f}s")  # 95%


if __name__ == "__main__":
    signing_stress_test()
